import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{r as d,o as n,c as r,f as l,a as e,b as o,d as t,e as a}from"./app-55e604a5.js";const p={},i=e("blockquote",null,[e("p",null,"CS144 的一些准备工作")],-1),h=a('<h1 id="选修原因" tabindex="-1"><a class="header-anchor" href="#选修原因" aria-hidden="true">#</a> 选修原因</h1><p>开始学习 <code>CS144</code> 这门课程并不是因为想学计网（当然可能也是有点想的，因为发现自己在这方面还是很欠缺），而是因为这门课程的实验是使用 <code>C++</code> 来构建出一个 <code>TCP</code> 协议栈。回顾前两年的学习，我发现我没有一门语言称得上擅长，<code>C</code> 无法做到 <code>xv6</code> 中那样熟练，<code>Java</code> 也并不清楚其各种机制特性，<code>Python</code> 也只是明白基础语法而无法做到 <code>Pythonic</code>，甚至连最常使用的 <code>C++</code> 也只是 <code>C with STL</code> 甚至 <code>STL</code> 也并不是那么熟练。因此选择了这门课程来锻炼自己的 <code>C++</code> 能力。</p><h1 id="环境准备" tabindex="-1"><a class="header-anchor" href="#环境准备" aria-hidden="true">#</a> 环境准备</h1><h2 id="方案一" tabindex="-1"><a class="header-anchor" href="#方案一" aria-hidden="true">#</a> 方案一</h2>',4),u={href:"https://stanford.edu/class/cs144/vm_howto/",target:"_blank",rel:"noopener noreferrer"},B=a(`<blockquote><p>我没有采用这个方案，因为我电脑上的 <code>VM</code> 太过拉跨……日常死机，可能是电脑配置太差劲了</p></blockquote><h2 id="方案二" tabindex="-1"><a class="header-anchor" href="#方案二" aria-hidden="true">#</a> 方案二</h2><p>如果你有一台 <code>Linux</code> 系统的电脑，直接用（可惜我没有）</p><h2 id="方案三" tabindex="-1"><a class="header-anchor" href="#方案三" aria-hidden="true">#</a> 方案三</h2><p>使用 <code>docker</code> 进行实验，你可以从头开始配置环境，也可以使用好心人配置好上传的 <code>docker</code>。用 <code>docker</code> 而不是 <code>WSL</code> 的原因是我有点害怕实现协议栈时会导致电脑网络出问题，而使用 <code>docker</code> 并不会出现这种问题，直接重新构建 <code>container</code> 就行。</p><p>此方案的使用方法为：</p><p>安装 <code>docker</code> 后，打开 <code>cmd</code> ，输入命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pull</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">vidocqh/cs144:latest</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>随后创建容器：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">container</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-v</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">vidocqh/cs144:lastest</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/bin/bash</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这样就可以开始 <code>Lab0</code> 了</p><h1 id="f-q" tabindex="-1"><a class="header-anchor" href="#f-q" aria-hidden="true">#</a> F&amp;Q</h1><p>不用 <code>WSL</code> 还有一个很重要的原因是因为实验必须依赖真实的 <code>Linux</code> 环境，否则会出现一系列莫名其妙过不去的点，但这些过不去的点又和你编写的代码没有一点关系，为了身心健康考虑还是不要使用 <code>WSL</code> 了。（<code>WSL2</code> 可能可以，但是 <code>WSL2</code> 的文件系统和本机不互通，也是一个很大的问题，不如使用 <code>docker</code>）</p>`,13);function b(m,_){const c=d("ExternalLinkIcon");return n(),r("div",null,[i,l("more"),h,e("p",null,[o("按照课程官网说明，我们可以使用官方准备好的 VM 直接进行操作，具体可参见课程网站"),e("a",u,[o("Setting up your CS144 VM (stanford.edu)"),t(c)])]),B])}const k=s(p,[["render",b],["__file","CS144-Env.html.vue"]]);export{k as default};
